-- ========== 3: Authenticating Art (過去問風) ==========
INSERT INTO public.reading_passages (level, genre, passage_type, body, title, content)
VALUES (
  '1級', 'expository', 'long_fill',
  E'Authenticating Art\n\nSome artists are known for recurring motifs—melting forms, dreamlike landscapes, or themes of decay and transformation. At times a painter may __BLANK__: curators examining one such work with advanced imaging discovered a hidden portrait beneath the visible surface, suggesting the artist had reused the canvas or reworked an earlier idea. Such findings remind us that the creation of art is often a process of layers and revisions.\n\nWhen a museum prepared an exhibition, it wished to include a particular painting attributed to this artist. The curators noticed, however, that the work differed from his known style of that period—sparser composition, different brushwork, and none of his characteristic motifs. They could not trace its ownership with certainty. __BLANK__. Was the painting really by the master, or had it been misattributed?\n\nA breakthrough came when staff found a photograph of a pavilion the artist had designed for a world fair. The painting in question turned out to be one panel of a larger mural that had been dismantled. __BLANK__: the work had been separated from its original context and its provenance had been lost. The museum reclassified and redated the painting accordingly, and researchers continue to investigate how and why it was detached from the larger piece.',
  'Authenticating Art',
  E'Authenticating Art\n\nSome artists are known for recurring motifs—melting forms, dreamlike landscapes, or themes of decay and transformation. At times a painter may __BLANK__: curators examining one such work with advanced imaging discovered a hidden portrait beneath the visible surface, suggesting the artist had reused the canvas or reworked an earlier idea. Such findings remind us that the creation of art is often a process of layers and revisions.\n\nWhen a museum prepared an exhibition, it wished to include a particular painting attributed to this artist. The curators noticed, however, that the work differed from his known style of that period—sparser composition, different brushwork, and none of his characteristic motifs. They could not trace its ownership with certainty. __BLANK__. Was the painting really by the master, or had it been misattributed?\n\nA breakthrough came when staff found a photograph of a pavilion the artist had designed for a world fair. The painting in question turned out to be one panel of a larger mural that had been dismantled. __BLANK__: the work had been separated from its original context and its provenance had been lost. The museum reclassified and redated the painting accordingly, and researchers continue to investigate how and why it was detached from the larger piece.'
);
