-- ========== 4: Two Approaches to History (過去問風) ==========
INSERT INTO public.reading_passages (level, genre, passage_type, body, title, content)
VALUES (
  '1級', 'expository', 'long_fill',
  E'Two Approaches to History\n\nOne ancient historian is often called the father of history. His great work drew on travels, oral accounts, and a willingness to weigh conflicting versions and highlight inconsistencies. He examined mythological elements with an unprecedented level of skepticism for his time. What sets his masterpiece apart from earlier chronicles is his __BLANK__: he did not simply record what he was told but scrutinized sources for plausibility and bias.\n\nAnother historian, his younger contemporary, wrote a detailed account of a long war between rival powers. His writing __BLANK__: he concentrated almost entirely on political and military events, with little of the cultural or ethnographic scope of his predecessor. His pragmatic analysis of statecraft and the rise and fall of empires influenced later thinkers from antiquity through the Renaissance and beyond. Statesmen and philosophers alike drew on his work to understand how power operates.\n\nThose influenced by the second historian __BLANK__. They looked to the past not for entertainment or broad narrative but for lessons applicable to their own times. In recent decades, however, the first historian has enjoyed a revival: his willingness to include diverse perspectives and social history, once dismissed by some as irrelevant, is now seen as essential to a rich and multifaceted understanding of the past.',
  'Two Approaches to History',
  E'Two Approaches to History\n\nOne ancient historian is often called the father of history. His great work drew on travels, oral accounts, and a willingness to weigh conflicting versions and highlight inconsistencies. He examined mythological elements with an unprecedented level of skepticism for his time. What sets his masterpiece apart from earlier chronicles is his __BLANK__: he did not simply record what he was told but scrutinized sources for plausibility and bias.\n\nAnother historian, his younger contemporary, wrote a detailed account of a long war between rival powers. His writing __BLANK__: he concentrated almost entirely on political and military events, with little of the cultural or ethnographic scope of his predecessor. His pragmatic analysis of statecraft and the rise and fall of empires influenced later thinkers from antiquity through the Renaissance and beyond. Statesmen and philosophers alike drew on his work to understand how power operates.\n\nThose influenced by the second historian __BLANK__. They looked to the past not for entertainment or broad narrative but for lessons applicable to their own times. In recent decades, however, the first historian has enjoyed a revival: his willingness to include diverse perspectives and social history, once dismissed by some as irrelevant, is now seen as essential to a rich and multifaceted understanding of the past.'
);
