-- ========== 10: The Nature of Genius ==========
INSERT INTO public.reading_passages (level, genre, passage_type, body, title, content)
VALUES (
  '1級', 'expository', 'long_fill',
  E'The Nature of Genius\n\nGenius has been attributed to divine inspiration, exceptional genes, or simply countless hours of practice. Modern research suggests that __BLANK__. High achievement in fields from music to mathematics usually requires both innate aptitude and deliberate practice over many years. Prodigies exist, but most experts in any domain have accumulated thousands of hours of focused effort. The "ten-year rule"—that it takes at least a decade to master a complex skill—has been observed across disciplines.\n\nCreativity often involves making connections between seemingly unrelated ideas. Some of the most celebrated innovations arose when someone applied a concept from one field to another. __BLANK__: breakthroughs are not random but often occur when a prepared mind encounters the right problem in the right context. Chance favors the prepared mind, as the saying goes.\n\n__BLANK__. Cultures that value innovation tend to reward risk-taking and tolerate failure. Educational systems that encourage curiosity and interdisciplinary thinking may produce more people who can combine ideas in novel ways. The myth of the lone genius obscures the social and institutional factors that enable exceptional achievement. Genius may be rare, but the conditions that nurture it can be cultivated.',
  'The Nature of Genius',
  E'The Nature of Genius\n\nGenius has been attributed to divine inspiration, exceptional genes, or simply countless hours of practice. Modern research suggests that __BLANK__. High achievement in fields from music to mathematics usually requires both innate aptitude and deliberate practice over many years. Prodigies exist, but most experts in any domain have accumulated thousands of hours of focused effort. The "ten-year rule"—that it takes at least a decade to master a complex skill—has been observed across disciplines.\n\nCreativity often involves making connections between seemingly unrelated ideas. Some of the most celebrated innovations arose when someone applied a concept from one field to another. __BLANK__: breakthroughs are not random but often occur when a prepared mind encounters the right problem in the right context. Chance favors the prepared mind, as the saying goes.\n\n__BLANK__. Cultures that value innovation tend to reward risk-taking and tolerate failure. Educational systems that encourage curiosity and interdisciplinary thinking may produce more people who can combine ideas in novel ways. The myth of the lone genius obscures the social and institutional factors that enable exceptional achievement. Genius may be rare, but the conditions that nurture it can be cultivated.'
);
